module RefModule(clk, reset, D, Q);
    input clk, reset, D;
    output reg Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset) begin
            Q <= 1'b0;
        end else begin
            Q <= D;
        end
    end
endmodule
